rule.query:
{
  "selection_img": {
    "Image|endswith": "/curl"
  },
  "selection_cli": [
    {
      "CommandLine|contains": [
        " --form",
        " --upload-file ",
        " --data ",
        " --data-"
      ]
    },
    {
      "CommandLine|re": "\\s-[FTd]\\s"
    }
  ],
  "filter_optional_localhost": {
    "CommandLine|contains": [
      "://localhost",
      "://127.0.0.1"
    ]
  },
  "condition": "all of selection_* and not 1 of filter_optional_*"
}
